import{_ as l,o as e,c as i,a1 as r}from"./chunks/framework.hVCBBfmZ.js";const t="/images/analytics.png",b=JSON.parse('{"title":"App 埋点 SDK 设计","description":"","frontmatter":{"title":"App 埋点 SDK 设计","date":"2025-08-20T10:01:23.000Z","recommend":false},"headers":[],"relativePath":"posts/analyticsSDK.md","filePath":"posts/analyticsSDK.md"}'),p={name:"posts/analyticsSDK.md"};function o(n,a,h,s,d,u){return e(),i("div",null,[...a[0]||(a[0]=[r('<p>适用平台 iOS / Android / HarmonyOS（可扩展至 Web、小程序）</p><h2 id="事件采集-tracker" tabindex="-1">事件采集 Tracker <a class="header-anchor" href="#事件采集-tracker" aria-label="Permalink to &quot;事件采集 Tracker&quot;">​</a></h2><h3 id="自动采集" tabindex="-1">自动采集 <a class="header-anchor" href="#自动采集" aria-label="Permalink to &quot;自动采集&quot;">​</a></h3><ul><li><p>页面曝光，每次露出都触发，支持设置业务参数，页面停留时长，后端根据前端发送的页面曝光时间和后台停留时间计算，页面来源（a-b-c，c-b，b 的来源是 c）</p></li><li><p>登录/退出，不发送事件，只修改本地存储的 userId</p></li><li><p>App 生命周期（冷启动/热启动/退后台（杀掉），上滑并杀掉 app 会先走“退后台”回调方法，可在这里统计退出事件</p></li><li><p>按钮/图片/Cell 点击事件</p></li></ul><h3 id="手动采集" tabindex="-1">手动采集 <a class="header-anchor" href="#手动采集" aria-label="Permalink to &quot;手动采集&quot;">​</a></h3><ul><li><p>视图曝光（SDK 提供支持，然后根据需求手动去埋），支持 Banner轮播图/List列表 Item 曝光，曝光比例暂不考虑</p></li><li><p>常规业务埋点</p></li></ul><h2 id="数据处理-databuffer" tabindex="-1">数据处理 DataBuffer <a class="header-anchor" href="#数据处理-databuffer" aria-label="Permalink to &quot;数据处理 DataBuffer&quot;">​</a></h2><h3 id="数据内容" tabindex="-1">数据内容 <a class="header-anchor" href="#数据内容" aria-label="Permalink to &quot;数据内容&quot;">​</a></h3><h4 id="基础数据" tabindex="-1">基础数据 <a class="header-anchor" href="#基础数据" aria-label="Permalink to &quot;基础数据&quot;">​</a></h4><ul><li><p>基础属性（设备/版本/渠道/时间戳(客户端时间)/事件ID和类型/sessionId等），事件ID和sessionId 用于对埋点数据排序，需要在冷启动和切换用户时更新，退到后台达到指定时间再返回到 app 时也需要更新（app和小程序用5分钟，web用30分钟）</p></li><li><p>用户属性（匿名ID/用户ID），匿名ID用 UUID + KeyChain 实现，不同端实现方式相似</p></li><li><p>埋点平台ID，冷启动和登录后调接口拿，和匿名ID一起存在 Keychain</p></li></ul><h4 id="业务数据" tabindex="-1">业务数据 <a class="header-anchor" href="#业务数据" aria-label="Permalink to &quot;业务数据&quot;">​</a></h4><ul><li><p>公共属性（城市/影院）</p></li><li><p>业务属性（movieId/movieName），类型支持数字和字符串</p></li></ul><h4 id="h5-埋点数据" tabindex="-1">H5 埋点数据 <a class="header-anchor" href="#h5-埋点数据" aria-label="Permalink to &quot;H5 埋点数据&quot;">​</a></h4><ul><li>App 内嵌 H5 的事件，由 App 来发（基础数据由 App 获取，H5 发送业务属性）</li></ul><h3 id="数据缓存" tabindex="-1">数据缓存 <a class="header-anchor" href="#数据缓存" aria-label="Permalink to &quot;数据缓存&quot;">​</a></h3><ul><li><p>内存缓存（Queue）</p></li><li><p>本地缓存（SQLite 加密存储），冷启动时检查，删除 30 天前的数据（事务）</p></li><li><p>数据转移规则（50条/15秒/退后台(被杀)），防止数据因崩溃或断网丢失，避免内存暴涨和频繁读写文件，以及保障数据完整性，转移过程：专有Queue/异步/事务</p></li></ul><h2 id="上报-uploader" tabindex="-1">上报 Uploader <a class="header-anchor" href="#上报-uploader" aria-label="Permalink to &quot;上报 Uploader&quot;">​</a></h2><ul><li><p>上报频率控制（冷启动、定时发送（默认 15 秒）、条数触发（默认 100 条））</p></li><li><p>数据压缩（GZIP）</p></li><li><p>数据加密（AES）</p></li><li><p>数据格式（Protobuf）</p></li><li><p>上传流量控制（WIFI/5G）</p></li></ul><h2 id="全局配置-config" tabindex="-1">全局配置 Config <a class="header-anchor" href="#全局配置-config" aria-label="Permalink to &quot;全局配置 Config&quot;">​</a></h2><ul><li><p>API 远端控制（采集开关（API 按渠道控制开关）/每次上报数量/上传间隔/sessionId 更新时间），忽略接口返回的无效数据，0，“”</p></li><li><p>App 本地控制（是否输出日志/视图曝光比例/要忽略的页面（无意义的容器页面）等）</p></li></ul><h2 id="日志与调试" tabindex="-1">日志与调试 <a class="header-anchor" href="#日志与调试" aria-label="Permalink to &quot;日志与调试&quot;">​</a></h2><ul><li><p>支持在 IDE 输出日志（SDK初始化结果/埋点数据记录/上报结果等），线上关掉</p></li><li><p>QA 环境支持抓包</p></li></ul><h2 id="其它" tabindex="-1">其它 <a class="header-anchor" href="#其它" aria-label="Permalink to &quot;其它&quot;">​</a></h2><ul><li><p>隐私合规方面需要产品去修改相关文档，说明采集数据用途</p></li><li><p>异常隔离，埋点功能出问题不能影响到 App 使用</p></li></ul><h2 id="导图版" tabindex="-1">导图版 <a class="header-anchor" href="#导图版" aria-label="Permalink to &quot;导图版&quot;">​</a></h2><p><img src="'+t+'" alt="App 埋点 SDK 设计思维导图" title="App 埋点 SDK 设计思维导图"></p>',26)])])}const f=l(p,[["render",o]]);export{b as __pageData,f as default};
